<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Mini Desktop</title>
<style>
  body,html{margin:0;padding:0;height:100%;overflow:hidden;font-family:sans-serif;background:#2e3436;color:#eee;}
  #desktop{position:absolute;width:100%;height:100%;background:url('data:image/svg+xml;base64,PHN2ZyB4bWxucz0iaHR0cDovL3d3dy53My5vcmcvMjAwMC9zdmciIHdpZHRoPSIxIiBoZWlnaHQ9IjEiPjxyZWN0IHg9IjAiIHk9IjAiIHdpZHRoPSIxIiBoZWlnaHQ9IjEiIGZpbGw9IiMyNzJmMzYiIC8+PC9zdmc+') repeat;}
  #taskbar{position:absolute;bottom:0;width:100%;height:40px;background:#1c1e21;border-top:1px solid #555;padding:5px 10px;box-sizing:border-box;}
  .launcher{display:inline-block;margin-right:10px;padding:5px 10px;background:#3a3f44;color:#eee;border-radius:4px;cursor:pointer;}
  .window{position:absolute;width:400px;height:300px;background:#2e3436;border:1px solid #555;border-radius:4px;box-shadow:0 0 10px rgba(0,0,0,.5);overflow:hidden;}
  .win-header{background:#3a3f44;color:#eee;padding:5px;font-weight:bold;cursor:pointer;display:flex;justify-content:space-between;align-items:center;}
  .win-close{cursor:pointer;background:none;border:none;color:#eee;font-size:16px;}
  #files-window,#notepad-window{display:none;}
  /* Files app */
  #files-path{padding:5px;background:#3a3f44;color:#eee;}
  #file-list{padding:10px;overflow:auto;height:calc(100% - 60px);}
  .fs-item{cursor:pointer;padding:2px 0;}
  .fs-item:hover{background:#4b5158;}
  /* Notepad */
  #tabs{display:flex;background:#3a3f44;color:#eee;padding:5px;}
  .tab{padding:5px 10px;margin-right:2px;cursor:pointer;border-radius:4px 4px 0 0;background:#3a3f44;}
  .tab.active{background:#2e3436;}
  #new-tab{margin-left:auto;padding:5px 10px;background:#3a3f44;color:#eee;border:none;border-radius:4px;cursor:pointer;}
  #editor{width:100%;height:calc(100% - 40px);border:none;background:#2e3436;color:#eee;font-family:monospace;font-size:14px;padding:10px;box-sizing:border-box;}
</style>
</head>
<body>
<div id="desktop">
  <div id="files-window" class="window" style="top:50px;left:50px;">
    <div class="win-header">Files<span class="win-close">&times;</span></div>
    <div id="files-path">/</div>
    <div id="file-list"></div>
  </div>

  <div id="notepad-window" class="window" style="top:80px;left:200px;">
    <div class="win-header">Notepad<span class="win-close">&times;</span></div>
    <div id="tabs"><button id="new-tab">+</button></div>
    <textarea id="editor"></textarea>
  </div>

  <div id="taskbar">
    <div id="open-files" class="launcher">Files</div>
    <div id="open-notepad" class="launcher">Notepad</div>
  </div>
</div>

<script>
/* ---------- Files App ---------- */
const fileSystem = {
  '/': {bin:{}, etc:{}, home:{user:{Documents:{}, Downloads:{}, Pictures:{}}}, usr:{}, var:{}}
};
let currentPath = '/';
function renderFiles() {
  const list=document.getElementById('file-list');
  list.innerHTML='';
  const parts=currentPath.split('/').filter(Boolean);
  let node=fileSystem['/'];
  for(const p of parts){node=node[p];}
  Object.keys(node).forEach(name=>{
    const el=document.createElement('div');
    el.className='fs-item';
    el.textContent=name;
    if(typeof node[name]==='object'){
      el.addEventListener('dblclick',()=>{currentPath+=name+'/';renderFiles();});
    }
    list.appendChild(el);
  });
}
document.getElementById('files-path').addEventListener('click',()=>{
  const parts=currentPath.split('/').filter(Boolean);
  if(parts.length>0){parts.pop();currentPath='/' + parts.join('/') + '/';if(currentPath==='//')currentPath='/';renderFiles();}
});
function initFiles(){renderFiles();}

/* ---------- Notepad App ---------- */
let tabs=[];
let activeTab=0;
const STORAGE_KEY='notepad-tabs';
function loadTabs(){
  const data=localStorage.getItem(STORAGE_KEY);
  if(data){tabs=JSON.parse(data);}else{tabs=[{title:'Untitled',content:''}];}
}
function saveTabs(){localStorage.setItem(STORAGE_KEY,JSON.stringify(tabs));}
function renderTabs(){
  const tabsEl=document.getElementById('tabs');
  tabsEl.innerHTML='<button id="new-tab">+</button>';
  tabs.forEach((t,i)=>{
    const btn=document.createElement('div');btn.className='tab';btn.textContent=t.title;btn.dataset.idx=i;
    if(i===activeTab)btn.classList.add('active');
    btn.addEventListener('click',()=>{switchTab(parseInt(btn.dataset.idx));});
    tabsEl.appendChild(btn);
  });
}
function switchTab(idx){
  activeTab=idx;
  document.getElementById('editor').value=tabs[idx].content;
  renderTabs();
}
document.getElementById('new-tab').addEventListener('click',()=>{
  const title='Untitled '+(tabs.length+1);
  tabs.push({title,content:''});
  switchTab(tabs.length-1);
});
document.getElementById('editor').addEventListener('input',(e)=>{
  tabs[activeTab].content=e.target.value;
  saveTabs();
});
function initNotepad(){loadTabs();renderTabs();switchTab(activeTab);}

/* ---------- Window Controls ---------- */
function showWindow(id){document.getElementById(id).style.display='block';}
function hideWindow(id){document.getElementById(id).style.display='none';}
document.getElementById('open-files').addEventListener('click',()=>showWindow('files-window'));
document.getElementById('open-notepad').addEventListener('click',()=>{showWindow('notepad-window');initNotepad();});
document.querySelectorAll('.win-close').forEach(btn=>{
  btn.addEventListener('click',()=>{
    hideWindow(btn.parentNode.parentNode.id);
  });
});

/* ---------- Init ---------- */
window.onload=function(){
  initFiles();
};
</script>
</body>
</html>
